// Cellular Tapestry - Evolving Grid Automata

let grid, nextGrid, ageGrid;
let cols, rows, cellSize;
let prevParams = '';
let genCount = 0;
let frameAccum = 0;
let rule110Row = 0;

const PALETTES = {
  thermal: [[0,0,80],[80,0,120],[200,50,50],[255,160,0],[255,255,100]],
  ocean: [[0,20,60],[0,60,120],[0,120,180],[60,180,220],[180,230,255]],
  forest: [[10,30,10],[30,80,20],[60,140,40],[120,180,60],[200,230,120]],
  neon: [[255,0,100],[0,255,150],[200,0,255],[255,255,0],[0,200,255]],
  pastel: [[255,180,200],[180,220,255],[200,255,200],[255,240,180],[220,200,255]],
  cosmic: [[20,0,40],[80,0,120],[0,50,150],[200,0,200],[255,200,255]],
  autumn: [[100,30,0],[180,80,20],[220,150,30],[180,120,40],[140,60,10]],
  grayscale: [[30,30,30],[80,80,80],[130,130,130],[190,190,190],[240,240,240]]
};

function getGridSize(v) {
  const m = {chunky:12, coarse:20, medium:40, fine:60, ultra:80, pixel:120};
  return m[v] || 40;
}

function getEvolutionFrames(v) {
  const m = {frozen:999999, slow:15, medium:6, fast:3, rapid:1, instant:0};
  return m[v] || 6;
}

function getMutationProb(v) {
  const m = {none:0, rare:0.0005, occasional:0.002, frequent:0.008, constant:0.02, burst:-1};
  return m[v] || 0;
}

function initGrid(pattern, c, r) {
  grid = new Uint8Array(c * r);
  nextGrid = new Uint8Array(c * r);
  ageGrid = new Float32Array(c * r);
  genCount = 0;
  rule110Row = 0;

  if (pattern === 'random') {
    for (let i = 0; i < c * r; i++) grid[i] = Math.random() > 0.5 ? 1 : 0;
  } else if (pattern === 'center_seed') {
    let cx = Math.floor(c/2), cy = Math.floor(r/2);
    for (let dx = -2; dx <= 2; dx++) {
      for (let dy = -2; dy <= 2; dy++) {
        let idx = (cy+dy)*c+(cx+dx);
        if (idx >= 0 && idx < c*r) grid[idx] = 1;
      }
    }
  } else if (pattern === 'diagonal') {
    for (let i = 0; i < Math.min(c,r); i++) {
      grid[i*c+i] = 1;
      if (i < c-1) grid[i*c+i+1] = 1;
    }
  } else if (pattern === 'glider_gun') {
    // Gosper glider gun (simplified)
    let gun = [[1,5],[1,6],[2,5],[2,6],[11,5],[11,6],[11,7],[12,4],[12,8],[13,3],[13,9],[14,3],[14,9],[15,6],[16,4],[16,8],[17,5],[17,6],[17,7],[18,6],[21,3],[21,4],[21,5],[22,3],[22,4],[22,5],[23,2],[23,6],[25,1],[25,2],[25,6],[25,7],[35,3],[35,4],[36,3],[36,4]];
    for (let g of gun) {
      let idx = (g[0]+2)*c+(g[1]+2);
      if (idx >= 0 && idx < c*r) grid[idx] = 1;
    }
  } else if (pattern === 'border') {
    for (let x = 0; x < c; x++) { grid[x] = 1; grid[(r-1)*c+x] = 1; }
    for (let y = 0; y < r; y++) { grid[y*c] = 1; grid[y*c+c-1] = 1; }
  } else if (pattern === 'spiral') {
    let cx = c/2, cy = r/2;
    for (let a = 0; a < Math.PI*8; a += 0.1) {
      let rad = a * 1.5;
      let x = Math.floor(cx + Math.cos(a)*rad*0.5);
      let y = Math.floor(cy + Math.sin(a)*rad*0.5);
      if (x >= 0 && x < c && y >= 0 && y < r) grid[y*c+x] = 1;
    }
  }
}

function getCell(x, y, boundaryV) {
  if (x >= 0 && x < cols && y >= 0 && y < rows) return grid[y*cols+x];
  if (boundaryV === 'wrap') return grid[((y%rows+rows)%rows)*cols+((x%cols+cols)%cols)];
  if (boundaryV === 'mirror') {
    let mx = x < 0 ? -x : (x >= cols ? 2*cols-x-2 : x);
    let my = y < 0 ? -y : (y >= rows ? 2*rows-y-2 : y);
    mx = Math.max(0, Math.min(cols-1, mx));
    my = Math.max(0, Math.min(rows-1, my));
    return grid[my*cols+mx];
  }
  if (boundaryV === 'random') return Math.random() > 0.5 ? 1 : 0;
  if (boundaryV === 'decay') return 0;
  return 0; // fixed, infinite
}

function countNeighbors(x, y, bnd) {
  let count = 0;
  for (let dy = -1; dy <= 1; dy++) {
    for (let dx = -1; dx <= 1; dx++) {
      if (dx === 0 && dy === 0) continue;
      count += getCell(x+dx, y+dy, bnd) > 0 ? 1 : 0;
    }
  }
  return count;
}

function evolve(ruleSet, bnd) {
  if (ruleSet === 'rule_110') {
    // 1D automaton scrolling down
    if (rule110Row === 0) {
      // Initialize top row randomly if not already
      for (let x = 0; x < cols; x++) {
        if (grid[x] === 0 && Math.random() > 0.5) grid[x] = 1;
      }
      rule110Row = 1;
    }
    // Shift everything up
    for (let y = 0; y < rows - 1; y++) {
      for (let x = 0; x < cols; x++) {
        nextGrid[y*cols+x] = grid[(y+1)*cols+x];
      }
    }
    // Generate new bottom row from current bottom row
    let lastRow = rows - 1;
    for (let x = 0; x < cols; x++) {
      let l = getCell(x-1, lastRow, bnd) > 0 ? 1 : 0;
      let c = grid[lastRow*cols+x] > 0 ? 1 : 0;
      let r = getCell(x+1, lastRow, bnd) > 0 ? 1 : 0;
      let pattern = (l << 2) | (c << 1) | r;
      let rule110 = 0b01101110; // Rule 110
      nextGrid[lastRow*cols+x] = (rule110 >> pattern) & 1;
    }
    let tmp = grid; grid = nextGrid; nextGrid = tmp;
    return;
  }

  for (let y = 0; y < rows; y++) {
    for (let x = 0; x < cols; x++) {
      let idx = y * cols + x;
      let state = grid[idx];
      let n = countNeighbors(x, y, bnd);

      if (ruleSet === 'game_of_life') {
        nextGrid[idx] = (state === 1) ? (n === 2 || n === 3 ? 1 : 0) : (n === 3 ? 1 : 0);
      } else if (ruleSet === 'brians_brain') {
        // 0=off, 1=on, 2=dying
        if (state === 0) nextGrid[idx] = (n === 2) ? 1 : 0;
        else if (state === 1) nextGrid[idx] = 2;
        else nextGrid[idx] = 0;
      } else if (ruleSet === 'cyclic') {
        // N-state cyclic: advance if neighbor has next state
        let nStates = 6;
        let nextState = (state + 1) % nStates;
        let hasNext = false;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            if (getCell(x+dx, y+dy, bnd) === nextState) { hasNext = true; break; }
          }
          if (hasNext) break;
        }
        nextGrid[idx] = hasNext ? nextState : state;
      } else if (ruleSet === 'seeds') {
        // B2/S (born with 2 neighbors, never survives)
        nextGrid[idx] = (state === 0 && n === 2) ? 1 : 0;
      } else if (ruleSet === 'day_and_night') {
        // B3678/S34678
        if (state === 0) nextGrid[idx] = (n===3||n===6||n===7||n===8) ? 1 : 0;
        else nextGrid[idx] = (n===3||n===4||n===6||n===7||n===8) ? 1 : 0;
      } else if (ruleSet === 'highlife') {
        // B36/S23
        if (state === 0) nextGrid[idx] = (n===3||n===6) ? 1 : 0;
        else nextGrid[idx] = (n===2||n===3) ? 1 : 0;
      } else if (ruleSet === 'diamoeba') {
        // B35678/S5678
        if (state === 0) nextGrid[idx] = (n===3||n===5||n===6||n===7||n===8) ? 1 : 0;
        else nextGrid[idx] = (n===5||n===6||n===7||n===8) ? 1 : 0;
      } else {
        nextGrid[idx] = (state === 1) ? (n === 2 || n === 3 ? 1 : 0) : (n === 3 ? 1 : 0);
      }
    }
  }
  let tmp = grid; grid = nextGrid; nextGrid = tmp;
}

function samplePalette(palette, t) {
  t = Math.max(0, Math.min(1, t));
  let idx = t * (palette.length - 1);
  let i = Math.floor(idx);
  let f = idx - i;
  let c1 = palette[Math.min(i, palette.length - 1)];
  let c2 = palette[Math.min(i + 1, palette.length - 1)];
  return [c1[0]+(c2[0]-c1[0])*f, c1[1]+(c2[1]-c1[1])*f, c1[2]+(c2[2]-c1[2])*f];
}

p.setup = function() {
  p.createCanvas(600, 600);
};

p.draw = function() {
  let ruleV = p.getSynthVar('rule_set') || 'game_of_life';
  let resV = p.getSynthVar('grid_resolution') || 'medium';
  let shapeV = p.getSynthVar('cell_shape') || 'square';
  let palV = p.getSynthVar('color_palette') || 'thermal';
  let cmapV = p.getSynthVar('color_mapping') || 'state';
  let initV = p.getSynthVar('initial_pattern') || 'random';
  let speedV = p.getSynthVar('evolution_speed') || 'medium';
  let fadeV = p.getSynthVar('fade_mode') || 'none';
  let gridLV = p.getSynthVar('grid_lines') || 'none';
  let bndV = p.getSynthVar('boundary') || 'wrap';
  let mutV = p.getSynthVar('mutation_rate') || 'none';

  let gridSz = getGridSize(resV);
  let params = ruleV + resV + initV + bndV;

  // Re-init if structural params changed
  if (params !== prevParams) {
    prevParams = params;
    cols = gridSz;
    rows = gridSz;
    cellSize = 600 / gridSz;
    initGrid(initV, cols, rows);
  }

  let palette = PALETTES[palV] || PALETTES.thermal;
  let evoFrames = getEvolutionFrames(speedV);
  let mutProb = getMutationProb(mutV);

  // Evolution step
  frameAccum++;
  if (frameAccum >= evoFrames) {
    frameAccum = 0;
    evolve(ruleV, bndV);
    genCount++;

    // Update age grid
    for (let i = 0; i < cols * rows; i++) {
      if (grid[i] > 0) ageGrid[i] = Math.min(ageGrid[i] + 1, 200);
      else if (fadeV !== 'none') ageGrid[i] = Math.max(ageGrid[i] - 0.5, 0);
      else ageGrid[i] = 0;
    }

    // Mutations
    if (mutProb === -1) { // burst
      if (genCount % 60 === 0) {
        for (let i = 0; i < cols*rows*0.05; i++) {
          let ri = Math.floor(Math.random()*cols*rows);
          grid[ri] = grid[ri] > 0 ? 0 : 1;
        }
      }
    } else if (mutProb > 0) {
      for (let i = 0; i < cols*rows; i++) {
        if (Math.random() < mutProb) grid[i] = grid[i] > 0 ? 0 : 1;
      }
    }
  }

  // Draw
  p.background(15);
  p.noStroke();

  for (let y = 0; y < rows; y++) {
    for (let x = 0; x < cols; x++) {
      let idx = y * cols + x;
      let state = grid[idx];
      let age = ageGrid[idx];
      let px = x * cellSize;
      let py = y * cellSize;

      // Skip empty cells with no fade
      if (state === 0 && age <= 0 && fadeV === 'none') continue;

      // Color
      let colorT = 0;
      let alpha = 255;

      if (cmapV === 'state') {
        if (ruleV === 'brians_brain') colorT = state / 2;
        else if (ruleV === 'cyclic') colorT = state / 6;
        else colorT = state > 0 ? 0.8 : 0.1;
      } else if (cmapV === 'age') {
        colorT = Math.min(1, age / 50);
      } else if (cmapV === 'neighbors') {
        let n = countNeighbors(x, y, bndV);
        colorT = n / 8;
      } else if (cmapV === 'gradient') {
        colorT = (x / cols + y / rows) / 2;
      } else if (cmapV === 'random') {
        colorT = ((x * 7 + y * 13 + genCount) % 100) / 100;
      } else { // pulse
        colorT = (Math.sin(p.frameCount * 0.05 + x * 0.2 + y * 0.2) + 1) / 2;
      }

      if (state === 0 && age > 0) {
        alpha = Math.min(255, age * 20);
        if (fadeV === 'ghost') alpha *= 0.3;
        else if (fadeV === 'afterglow') { alpha *= Math.max(0, 1 - (genCount % 10) / 5); colorT = Math.min(1, colorT + 0.3); }
        else if (fadeV === 'echo') alpha *= 0.5;
        else if (fadeV === 'psychedelic') { colorT = (colorT + p.frameCount * 0.01) % 1; alpha *= 0.6; }
        else if (fadeV === 'trail') alpha *= 0.6;
      }

      if (alpha < 5) continue;

      let col = samplePalette(palette, colorT);
      p.fill(col[0], col[1], col[2], alpha);

      let margin = cellSize * 0.08;
      let sz = cellSize - margin * 2;

      if (shapeV === 'square') {
        p.rect(px + margin, py + margin, sz, sz);
      } else if (shapeV === 'circle') {
        p.ellipse(px + cellSize/2, py + cellSize/2, sz, sz);
      } else if (shapeV === 'diamond') {
        p.push();
        p.translate(px + cellSize/2, py + cellSize/2);
        p.rotate(Math.PI / 4);
        p.rect(-sz*0.35, -sz*0.35, sz*0.7, sz*0.7);
        p.pop();
      } else if (shapeV === 'hexagon') {
        p.push();
        p.translate(px + cellSize/2, py + cellSize/2);
        p.beginShape();
        for (let a = 0; a < 6; a++) {
          let angle = a * Math.PI / 3 - Math.PI / 6;
          p.vertex(Math.cos(angle)*sz*0.45, Math.sin(angle)*sz*0.45);
        }
        p.endShape(p.CLOSE);
        p.pop();
      } else if (shapeV === 'triangle') {
        let flip = (x + y) % 2 === 0;
        if (flip) p.triangle(px+margin, py+sz+margin, px+cellSize/2, py+margin, px+sz+margin, py+sz+margin);
        else p.triangle(px+margin, py+margin, px+cellSize/2, py+sz+margin, px+sz+margin, py+margin);
      } else { // organic
        let wobble = Math.sin(age * 0.3 + x + y) * sz * 0.1;
        p.ellipse(px + cellSize/2 + wobble, py + cellSize/2, sz * (0.8 + Math.sin(age*0.2)*0.2), sz);
      }
    }
  }

  // Grid lines
  if (gridLV !== 'none') {
    let glAlpha, glWeight;
    if (gridLV === 'subtle') { glAlpha = 25; glWeight = 0.5; }
    else if (gridLV === 'visible') { glAlpha = 60; glWeight = 1; }
    else if (gridLV === 'bold') { glAlpha = 120; glWeight = 2; }
    else if (gridLV === 'glow') { glAlpha = 40; glWeight = 2; }
    else if (gridLV === 'dashed') { glAlpha = 50; glWeight = 1; }
    else { glAlpha = 30; glWeight = 0.5; }

    if (gridLV === 'glow') {
      p.stroke(100, 150, 255, glAlpha);
    } else {
      p.stroke(255, 255, 255, glAlpha);
    }
    p.strokeWeight(glWeight);

    if (gridLV === 'dashed') {
      p.drawingContext.setLineDash([3, 3]);
    }

    for (let x = 0; x <= cols; x++) {
      p.line(x * cellSize, 0, x * cellSize, 600);
    }
    for (let y = 0; y <= rows; y++) {
      p.line(0, y * cellSize, 600, y * cellSize);
    }

    if (gridLV === 'dashed') {
      p.drawingContext.setLineDash([]);
    }
  }
};
